// ─────────────────────────────────────────────────────────────────────────────
// OpenScout web front-end taxonomy — machine-readable page + functionality map.
//
// Source of truth for the /studies/web-taxonomy Studio page. Generated by the
// `web-taxonomy` multi-agent workflow on 2026-06-07 (66 surfaces across
// 6 areas). Each screen was inventoried by reading the actual source in
// packages/web/client. Regenerate via the workflow rather than hand-editing entries.
//
// The AGENT_LENS_DEEP_DIVE section answers the "agent overview / message overlap"
// question: the many ways the app shows a single agent (Profile / Observe / Message
// / Inspector), what they share, where they diverge, and how to consolidate.
// ─────────────────────────────────────────────────────────────────────────────

export type WebArea = "home" | "agents" | "chat" | "search" | "ops" | "chrome";
export type TopNavKey = "home" | "agents" | "chat" | "search" | "ops";

/** One user-facing surface (routed screen, sub-view host, or chrome slot). */
export interface WebScreen {
  /** Human label. */
  name: string;
  /** Source file(s), repo-relative. */
  files: string[];
  /** The Route it renders under (view + mode/section), or 'component' / 'slot:*'. */
  route: string;
  /** One-line purpose. */
  purpose: string;
  /** Concrete things a user can do here. */
  actions: string[];
  /** What it reads — broker APIs, SSE/event streams, hooks, queries. */
  dataSources: string[];
  /** Tabs / lenses / modes within this surface. */
  subViews: string[];
  /** Notable shared components it composes. */
  sharedComponents: string[];
  /** Surfaces elsewhere that do a similar job (suspected duplication). */
  overlaps: string[];
}

export interface WebAreaGroup {
  id: WebArea;
  label: string;
  /** Top-nav key this area maps to, or null for cross-cutting chrome. */
  topNavKey: TopNavKey | null;
  screens: WebScreen[];
}

/** One "lens" onto a single agent in the agent-overview deep-dive. */
export interface AgentLens {
  name: string;
  surface: string;
  files: string[];
  shows: string[];
  dataSources: string[];
  uniqueTo: string[];
}

export interface ConsolidationOpportunity {
  idea: string;
  rationale: string;
  blockers: string[];
}

export interface AgentLensDeepDive {
  lenses: AgentLens[];
  sharedComponents: string[];
  divergences: string[];
  consolidationOpportunities: ConsolidationOpportunity[];
}

/** A cross-cutting structural finding spanning several surfaces. */
export interface WebTheme {
  title: string;
  detail: string;
  /** Exact WebScreen.name values this theme spans. */
  surfaces: string[];
}

/** A set of surfaces doing overlapping work + the consolidation move. */
export interface DuplicationCluster {
  label: string;
  surfaces: string[];
  opportunity: string;
}

/** Top-level executive synthesis of the whole web app. */
export interface WebTaxonomySummary {
  headline: string;
  themes: WebTheme[];
  duplicationClusters: DuplicationCluster[];
}

